nta.declaration:
// Place global declarations here.
clock globalTime;

//R0 = EGF
clock R0;
const int R0Init = 100;
const int R0Levels = 100;

//R1 = EGFR
clock R1;
const int R1Init = 0;
const int R1Levels = 100;

//R2 = EGFR internalization
clock R2;
const int R2Init = 0;
const int R2Levels = 100;

//R3 = ERK
clock R3;
const int R3Init = 0;
const int R3Levels = 100;

//R4 = ERK phosphatase
clock R4;
const int R4Init = 1;
const int R4Levels = 1;

//Reaction R4 (ERK phosphatase) --| R3 (ERK)
const double k_R4_R3 = 0.1;

//Reaction R2 (EGFR internalization) --| R1 (EGFR)
const double k_R2_R1 = 0.008;

//Reaction R1 (EGFR) --> R3 (ERK)
const double k_R1_R3 = 0.004;

//Reaction R0 (EGF) --> R1 (EGFR)
const double k_R0_R1 = 0.004;

//Reaction R1 (EGFR) --> R2 (EGFR internalization)
const double k_R1_R2 = 0.004;

template.declaration:
double rateR0() {
	return 0;
}

double boundedRateR0() {
	return 0;
}

double rateR1() {
	double R2_R1_r = k_R2_R1 * R2;
	double R0_R1_r = k_R0_R1 * R0;
	return  - R2_R1_r + R0_R1_r;
}

double boundedRateR1() {
	double r = rateR1();
	if (R1 + r > R1Levels) {
		return R1Levels - R1;
	} else if (R1 + r < 0) {
		return -R1;
	}
	return r;
}

double rateR2() {
	double R1_R2_r = k_R1_R2 * R1;
	return R1_R2_r;
}

double boundedRateR2() {
	double r = rateR2();
	if (R2 + r > R2Levels) {
		return R2Levels - R2;
	} else if (R2 + r < 0) {
		return -R2;
	}
	return r;
}

double rateR3() {
	double R4_R3_r = k_R4_R3 * R4;
	double R1_R3_r = k_R1_R3 * R1;
	return  - R4_R3_r + R1_R3_r;
}

double boundedRateR3() {
	double r = rateR3();
	if (R3 + r > R3Levels) {
		return R3Levels - R3;
	} else if (R3 + r < 0) {
		return -R3;
	}
	return r;
}

double rateR4() {
	return 0;
}

double boundedRateR4() {
	return 0;
}
